"""
Pytest test suite for API rate limiting requirements.

Requirements covered:
- 60 requests per minute per user (rate limit enforcement)
- 429 status code on overage
- Retry-After header on 429 response
- Negative paths: insufficient funds, unauthorised, exceeded limits
"""

import time
from collections import defaultdict
from datetime import datetime, timedelta
from http import HTTPStatus
from unittest.mock import MagicMock, patch

import pytest
import requests

# ---------------------------------------------------------------------------
# Constants
# ---------------------------------------------------------------------------

RATE_LIMIT = 60          # requests allowed per window
WINDOW_SECONDS = 60      # rolling window in seconds
BASE_URL = "https://api.example.com"
VALID_TOKEN = "Bearer valid-token-user-1"
VALID_TOKEN_USER2 = "Bearer valid-token-user-2"
INVALID_TOKEN = "Bearer invalid-token"
EXPIRED_TOKEN = "Bearer expired-token"
LOW_FUNDS_TOKEN = "Bearer low-funds-token"


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture
def api_session():
    """Return a requests Session with sensible defaults."""
    session = requests.Session()
    session.headers.update({"Content-Type": "application/json"})
    yield session
    session.close()


@pytest.fixture
def auth_headers():
    return {"Authorization": VALID_TOKEN}


@pytest.fixture
def auth_headers_user2():
    return {"Authorization": VALID_TOKEN_USER2}


@pytest.fixture
def invalid_headers():
    return {"Authorization": INVALID_TOKEN}


@pytest.fixture
def expired_headers():
    return {"Authorization": EXPIRED_TOKEN}


@pytest.fixture
def low_funds_headers():
    return {"Authorization": LOW_FUNDS_TOKEN}


@pytest.fixture
def mock_rate_limiter():
    """
    In-process token-bucket / sliding-window mock so tests run without
    a live server.  Maps user_token -> list[timestamp].
    """
    request_log: dict[str, list[float]] = defaultdict(list)

    def handle_request(token: str, endpoint: str = "/v1/resource", **kwargs):
        now = time.monotonic()

        # --- Auth checks ---------------------------------------------------
        if not token or token == "Bearer ":
            return _make_response(HTTPStatus.UNAUTHORIZED,
                                  {"error": "missing_token",
                                   "message": "Authorization header required"})

        if token == INVALID_TOKEN:
            return _make_response(HTTPStatus.UNAUTHORIZED,
                                  {"error": "invalid_token",
                                   "message": "Token is invalid"})

        if token == EXPIRED_TOKEN:
            return _make_response(HTTPStatus.UNAUTHORIZED,
                                  {"error": "token_expired",
                                   "message": "Token has expired"})

        # --- Funds check ---------------------------------------------------
        if token == LOW_FUNDS_TOKEN:
            return _make_response(HTTPStatus.PAYMENT_REQUIRED,
                                  {"error": "insufficient_funds",
                                   "message": "Account balance too low"})

        # --- Rate-limit check (sliding window) -----------------------------
        window_start = now - WINDOW_SECONDS
        # Prune old timestamps
        request_log[token] = [t for t in request_log[token] if t > window_start]

        if len(request_log[token]) >= RATE_LIMIT:
            oldest = request_log[token][0]
            retry_after = int(WINDOW_SECONDS - (now - oldest)) + 1
            return _make_response(
                HTTPStatus.TOO_MANY_REQUESTS,
                {"error": "rate_limit_exceeded",
                 "message": f"Rate limit of {RATE_LIMIT} req/min exceeded"},
                extra_headers={"Retry-After": str(retry_after),
                               "X-RateLimit-Limit"
